INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES ("vo_minigame_1004", 1, 1000101, 10001, 2, "ふっふっふ、これでカヤぴぃとボスを見返してやるです！", "vo_minigame_1004_top_1_000");
